firmware_template.source:
#include "interpolation.h"
float lerp(float a,float b,float t){return a+(b-a)*t;}
float map_range(float v,float imn,float imx,float omn,float omx){return omn+(v-imn)*(omx-omn)/(imx-imn);}
float clamp(float v,float mn,float mx){return v<mn?mn:(v>mx?mx:v);}
float smooth_step(float e0,float e1,float x){float t=clamp((x-e0)/(e1-e0),0,1);return t*t*(3-2*t);}
